class Provider {
    getSettings() {
        return {
            supportsAdult: false
        };
    }

    async search(opts) {
        try {
            if (opts.media && opts.media.mediaType !== "tv") {
                // EZTV is strictly for TV shows
                console.log("EZTV: mediaType is not tv, skipping");
                return [];
            }

            let imdbId = "";
            if (opts.media && opts.media.imdbId) {
                imdbId = opts.media.imdbId;
                if (imdbId.startsWith("tt")) {
                    imdbId = imdbId.substring(2);
                }
            }

            if (!imdbId) {
                console.log("EZTV: No IMDb ID provided for TV show, cannot search EZTV JSON API");
                return [];
            }

            console.log("EZTV: Searching for IMDb ID: " + imdbId);
            const url = "https://eztv.re/api/get-torrents?imdb_id=" + encodeURIComponent(imdbId) + "&limit=100";
            console.log("EZTV: Fetching URL: " + url);

            const res = await fetch(url);
            if (!res.ok) {
                throw new Error("HTTP error " + res.status);
            }

            const data = await res.json();
            if (!data || !data.torrents || data.torrents.length === 0) {
                console.log("EZTV: No torrents found");
                return [];
            }

            const results = [];
            for (const torrent of data.torrents) {
                const name = torrent.title || "";

                let sizeBytes = 0;
                if (torrent.size_bytes) {
                    sizeBytes = parseInt(torrent.size_bytes) || 0;
                }

                let infoHash = torrent.hash || "";
                const magnetLink = torrent.magnet_url || "";
                if (!infoHash && magnetLink) {
                    const match = magnetLink.match(/btih:([a-fA-F0-9]{40})/i);
                    if (match) {
                        infoHash = match[1];
                    }
                }

                results.push({
                    name: name,
                    date: new Date((torrent.date_released_unix || 0) * 1000).toISOString(),
                    size: sizeBytes,
                    formattedSize: this.bytesToHuman(sizeBytes),
                    seeders: torrent.seeds || 0,
                    leechers: torrent.peers || 0,
                    downloadCount: 0,
                    link: torrent.episode_url || "",
                    downloadUrl: torrent.torrent_url || "",
                    magnetLink: magnetLink,
                    infoHash: infoHash,
                    resolution: this.detectResolution(name),
                    confirmed: true
                });
            }

            console.log("EZTV: Found " + results.length + " torrents");
            return results;
        } catch (error) {
            console.error("EZTV search failed: " + error.message);
            return [];
        }
    }

    getTorrentInfoHash(torrent) {
        return torrent.infoHash || "";
    }

    getTorrentMagnetLink(torrent) {
        return torrent.magnetLink || "";
    }

    bytesToHuman(bytes) {
        if (bytes === 0) return "0 Bytes";
        const k = 1024;
        const sizes = ["Bytes", "KiB", "MiB", "GiB", "TiB"];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + " " + sizes[i];
    }

    detectResolution(name) {
        const titleLower = name.toLowerCase();
        if (titleLower.includes("2160p") || titleLower.includes("4k")) return "2160p";
        if (titleLower.includes("1080p")) return "1080p";
        if (titleLower.includes("720p")) return "720p";
        if (titleLower.includes("480p")) return "480p";
        return "";
    }
}
